    if not isinstance(config_filename, str) or not isinstance(crypt_signature, str):
        raise TypeError("config_filename and crypt_signature must be strings")

    expected_signature = TRUSTED_CONFIG_SIGNATURES.get(config_filename)
    if expected_signature is None:
        return None

    if crypt_signature != expected_signature:
        return None

    try:
        data = load_config_data(config_filename)
